import { spawnSync } from 'node:child_process';
import * as path from 'node:path';
export async function runRomeFix() {
    const root = process.cwd();
    const cmds = [
        ['rome', ['check', '--apply']],
        ['rome', ['format', '--write']],
        ['rome', ['check', '--apply', path.join(root, 'src')]],
        ['rome', ['check', '--apply', path.join(root, 'packages')]],
    ];
    for (const [cmd, args] of cmds) {
        console.log(`🛠 Running: ${cmd} ${args.join(' ')}`);
        spawnSync(cmd, args, {
            stdio: 'inherit',
            shell: true,
            cwd: root,
        });
    }
}
